var result,fileName,originCountrySelector=$("#origin-country-selector"),destinationCountrySelector=$("#destination-country-selector"),body=$("body"),githubDbFolder="https://github.com/cristacheda/nomad.expert/tree/gh-pages/data/documents/",availableCountries=[{code:"RO",name:"Romania",file:"romania.json"}];function buildOriginCountrySelector(e){originCountrySelector.append('<option value="">Selectează o țară</option>');for(let o=0;o<e.length;o++){var t=e[o];t&&originCountrySelector.append(`<option value="${t.file}">${t.name}</option>`)}}function buildDestinationCountrySelector(e){for(let o=0;o<e.length;o++){var t=e[o];t.documents&&destinationCountrySelector.append(`<option value="${t.code}">${t.name}</option>`)}}function findCountry(e,t){return t.find(t=>t.code===e)}function buildResults(e){var t=$("#info"),o=$("#comment"),n=$("#source"),i=$("#result");t.text(`Pentru a călători în ${e.name} ai nevoie de ${e.documents}.`),o.text(e.comment),n.html(`<a target="_blank" rel="noopener" href="${e.source}">Sursa informațiilor</a>`),i.show(),body.toggleClass("results-visible")}function buildEditLink(e){$("#edit").html(`<a target="_blank" rel="noopener" href="${githubDbFolder}/${e}"><i class="fal fa-edit"></i> Corectează informațiile</a>`)}buildOriginCountrySelector(availableCountries),originCountrySelector.change((function(){fileName=$(this).val(),$.getJSON("https://cristacheda.github.io/nomad.expert/data/documents/"+fileName,(function(e){buildDestinationCountrySelector(result=e)}))})),destinationCountrySelector.change((function(){buildResults(findCountry($(this).val(),result)),buildEditLink(fileName)})),$("#toggle-menu").click((function(){$("body").toggleClass("menu-visible")}));